$LP="$env:TEMP\driver-install-$(Get-Date -Format 'yyyyMMdd-HHmmss').log";$DP="$env:TEMP\driver-downloads";$ProgressPreference="SilentlyContinue";function WL([string]$M,[string]$L="INFO"){$ts=Get-Date -Format "yyyy-MM-dd HH:mm:ss";$log="[$ts] [$L] $M";Write-Host $log;Add-Content -Path $LP -Value $log -ErrorAction SilentlyContinue};function GetGPU{WL "Detecting GPU...";$gpu=@();Get-WmiObject Win32_VideoController -ErrorAction SilentlyContinue|Where-Object{$_.Name}|ForEach-Object{if($_.Name -like "*NVIDIA*"){$gpu+=@{Type="NVIDIA";Name=$_.Name;DeviceID=$_.PNPDeviceID;Model=$_.Name};WL "Found NVIDIA GPU: $($_.Name)"};if($_.Name -like "*AMD*" -or $_.Name -like "*Radeon*"){$gpu+=@{Type="AMD";Name=$_.Name;DeviceID=$_.PNPDeviceID;Model=$_.Name};WL "Found AMD GPU: $($_.Name)"};if($_.Name -like "*Intel*"){$gpu+=@{Type="Intel";Name=$_.Name;DeviceID=$_.PNPDeviceID;Model=$_.Name};WL "Found Intel GPU: $($_.Name)"}};return $gpu};function GetDev{WL "Detecting system devices...";$dev=@();$dc=@("Win32_NetworkAdapterConfiguration","Win32_SoundDevice","Win32_IDEController","Win32_USBController","Win32_SerialPort");$types=@("Network Adapters","Audio","Storage Controllers","USB Controllers","Serial/Parallel");for($i=0;$i -lt $dc.Count;$i++){Get-WmiObject $dc[$i] -ErrorAction SilentlyContinue|Where-Object{$_.Description -or $_.Name}|ForEach-Object{$dev+=@{Type=$types[$i];Name=if($_.Description){$_.Description}else{$_.Name}};WL "Found $($types[$i]): $(if($_.Description){$_.Description}else{$_.Name})"}};Get-WmiObject Win32_BaseBoard -ErrorAction SilentlyContinue|ForEach-Object{$dev+=@{Type="Motherboard";Name=$_.Manufacturer+" "+$_.Product};WL "Found Motherboard: $($_.Manufacturer) $($_.Product)"};return $dev};function GetSys{WL "Collecting system information...";$os=Get-WmiObject Win32_OperatingSystem;$proc=Get-WmiObject Win32_Processor;return @{OS=$os.Caption;OSBuild=$os.BuildNumber;Architecture=$os.OSArchitecture;Processor=$proc.Name}};function DlNV([hashtable]$g,[hashtable]$s){WL "Preparing NVIDIA driver..." "INFO";WL "NVIDIA driver URL: https://www.nvidia.com/Download/index.aspx" "INFO";WL "Visit: https://www.nvidia.com/Download/index.aspx to download NVIDIA drivers manually" "INFO"};function DlAMD([hashtable]$g,[hashtable]$s){WL "Preparing AMD driver..." "INFO";WL "AMD driver page: https://www.amd.com/en/technologies/radeon-software" "INFO";WL "Visit: https://www.amd.com/en/technologies/radeon-software to download AMD drivers manually" "INFO"};function DlINT([hashtable]$g,[hashtable]$s){WL "Preparing Intel driver..." "INFO";WL "Intel Arc page: https://www.intel.com/content/www/us/en/download/785597/intel-arc-graphics-driver.html" "INFO";WL "Visit: https://www.intel.com/content/www/us/en/download/785597/intel-arc-graphics-driver.html to download Intel drivers manually" "INFO"};function DlChip([hashtable]$s){WL "Detecting chipset drivers..." "INFO";$mb=Get-WmiObject Win32_BaseBoard -ErrorAction SilentlyContinue;if($mb){$mfg=$mb.Manufacturer.ToLower();if($mfg -like "*intel*"){WL "Intel Chipset: https://www.intel.com/content/www/us/en/download/17596/intel-chipset-device-software.html" "INFO"}elseif($mfg -like "*amd*"){WL "AMD Chipset: https://www.amd.com/en/support" "INFO"}}};function Main{Write-Host "========================================" -ForegroundColor Cyan;Write-Host "  Universal Driver Installer Script" -ForegroundColor Cyan;Write-Host "========================================" -ForegroundColor Cyan;WL "Script started";if(-not([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]"Administrator")){WL "ERROR: Administrator privileges required!" "ERROR";Write-Host "Please run PowerShell as Administrator." -ForegroundColor Red;exit 1};if(-not(Test-Path $DP)){New-Item -ItemType Directory -Path $DP|Out-Null};WL "Log file: $LP";Write-Host "";$gpu=GetGPU;$dev=GetDev;$sys=GetSys;Write-Host "`n========== DETECTED HARDWARE ==========" -ForegroundColor Green;Write-Host "GPUs detected: $($gpu.Count)" -ForegroundColor Green;$gpu|ForEach-Object{Write-Host "  - $($_.Type): $($_.Name)" -ForegroundColor Green};Write-Host "`nSystem devices detected: $($dev.Count)" -ForegroundColor Green;$dev|Select-Object -First 5|ForEach-Object{Write-Host "  - $($_.Type): $($_.Name)" -ForegroundColor Green};if($dev.Count -gt 5){Write-Host "  ... and $($dev.Count-5) more devices" -ForegroundColor Green};if($gpu.Count -eq 0 -and $dev.Count -eq 0){WL "No GPU or devices detected" "WARN";Write-Host "`nNo hardware requiring drivers detected." -ForegroundColor Yellow;exit 0};Write-Host "`n========== DRIVER ACQUISITION ==========" -ForegroundColor Green;$gpu|ForEach-Object{switch($_.Type){"NVIDIA"{DlNV $_ $sys};"AMD"{DlAMD $_ $sys};"Intel"{DlINT $_ $sys}}};DlChip $sys;Write-Host "`n========== NEXT STEPS ==========" -ForegroundColor Cyan;Write-Host "1. Download the drivers from the URLs above" -ForegroundColor Cyan;Write-Host "2. Run the installer executables" -ForegroundColor Cyan;Write-Host "3. Restart your computer after installation" -ForegroundColor Cyan;Write-Host "4. Log file saved to: $LP" -ForegroundColor Cyan;WL "Script completed"};Main;Read-Host "Press Enter to exit"
